def validate_email(value):
    s = str(value).strip()
    if s.count('@') != 1:
        return False
    local, domain = s.split('@')
    if not local or not domain:
        return False
    if '.' not in domain:
        return False
    parts = domain.split('.')
    if any(p == '' for p in parts):
        return False
    tld = parts[-1]
    if len(tld) < 2:
        return False
    return True

def validate_phone(value):
    digits = ''.join(ch for ch in str(value) if ch.isdigit())
    return len(digits) == 10

def validate_date(value):
    s = str(value).strip()
    if len(s) != 10:
        return False
    if s[4] != '-' or s[7] != '-':
        return False
    year_s, month_s, day_s = s[0:4], s[5:7], s[8:10]
    if not (year_s.isdigit() and month_s.isdigit() and day_s.isdigit()):
        return False
    month, day = int(month_s), int(day_s)
    return 1 <= month <= 12 and 1 <= day <= 31

def validate_linkedin(value):
    s = str(value).strip()
    valid_prefixes = [
        "https://www.linkedin.com/in/",
        "https://linkedin.com/in/"
    ]
    if not any(s.startswith(prefix) for prefix in valid_prefixes):
        return False
    # Extract the slug after /in/
    slug = s.split("/in/")[-1].rstrip("/")
    if not slug:
        return False
    allowed_chars = set("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_%")
    return all(ch in allowed_chars for ch in slug)

VALID_EMPLOYMENT_TYPES = {"full-time", "part-time", "contract", "intern"}
VALID_WORK_LOCATIONS   = {"remote", "hybrid", "on-site"}

REQUIRED_FIELDS = [
    "firstName", "lastName", "email", "phone", "jobTitle",
    "department", "startDate", "employmentType", "workLocation",
    "linkedInProfile", "jobId", "managerEmail"
]

results = []

for item in _items:
    data   = item["json"]
    errors = []

    # --- Required field presence ---
    for field in REQUIRED_FIELDS:
        if field not in data or data[field] is None or str(data[field]).strip() == "":
            errors.append(f"'{field}' is missing or empty")

    # --- Field-level validation ---
    if "email" in data and data["email"]:
        if not validate_email(data["email"]):
            errors.append(f"'email' is not a valid email address: {data['email']}")

    if "managerEmail" in data and data["managerEmail"]:
        if not validate_email(data["managerEmail"]):
            errors.append(f"'managerEmail' is not a valid email address: {data['managerEmail']}")

    if "phone" in data and data["phone"]:
        if not validate_phone(data["phone"]):
            errors.append(f"'phone' must be a 10-digit number: {data['phone']}")

    if "startDate" in data and data["startDate"]:
        if not validate_date(data["startDate"]):
            errors.append(f"'startDate' must be in YYYY-MM-DD format: {data['startDate']}")

    if "employmentType" in data and data["employmentType"]:
        if str(data["employmentType"]).strip().lower() not in VALID_EMPLOYMENT_TYPES:
            errors.append(f"'employmentType' must be one of: Full-Time, Part-Time, Contract, Intern. Got: {data['employmentType']}")

    if "workLocation" in data and data["workLocation"]:
        if str(data["workLocation"]).strip().lower() not in VALID_WORK_LOCATIONS:
            errors.append(f"'workLocation' must be one of: Remote, Hybrid, On-Site. Got: {data['workLocation']}")

    if "linkedInProfile" in data and data["linkedInProfile"]:
        if not validate_linkedin(data["linkedInProfile"]):
            errors.append(f"'linkedInProfile' is not a valid LinkedIn URL: {data['linkedInProfile']}")

    # --- Attach results ---
    item["json"]["validationPassed"] = len(errors) == 0
    item["json"]["validationErrors"] = errors

    results.append(item)

return results
